INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('af4dbf83f3040d95', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'runoff_rules', 'When does a primary election go to a runoff in Georgia?', '["What triggers a runoff?","Does the top vote-getter automatically win the primary?","Georgia 50 percent rule"]', 'If no candidate receives a majority (50% plus one vote) of the total votes cast for that office in the primary, the top two vote-getters automatically advance to a runoff election.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all partisan and nonpartisan primary elections in Georgia.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('5f061f52a9d7d9e5', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'runoff_rules', 'Are there runoffs in the general election?', '["Do general elections require a majority?","Can someone win a general election with 49 percent?","What happens if a third-party candidate forces the vote under 50 percent?"]', 'Yes. Under Georgia law, if no candidate receives a majority (50% plus one vote) of the votes in the general election, a runoff is held between the top two vote-getters. This applies to most state, local, and federal races, including U.S. Senate and U.S. House.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates appearing on a general election ballot.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('2f60e1ce70a990f8', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'How many weeks after the general election is the runoff?', '["General election runoff timing","When is the runoff held?","How much time do I have to campaign for a runoff?"]', 'Following the passage of the SB 202 election reforms, general election runoffs in Georgia are now held exactly four weeks (28 days) after the general election.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(4) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all state, local, and federal general election runoffs.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('d8289890699c4c23', 'GA', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 General Primary Election in Georgia?', '["Primary date 2026","When do voters vote in the primary?","Georgia primary election schedule"]', 'The 2026 General Primary and Nonpartisan Election is scheduled for Tuesday, May 19, 2026.', 'https://sos.ga.gov/sites/default/files/forms/2026%20Elections%20Calendar%20Summary.pdf', 'Georgia Secretary of State – 2026 Election Calendar Highlights', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to all voters and candidates participating in the Georgia primary.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('cce371d84238f8a5', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election in Georgia?', '["Election day 2026","What date is the November election?","Fall general election date"]', 'The 2026 General Election is scheduled for Tuesday, November 3, 2026.', 'https://sos.ga.gov/sites/default/files/forms/2026%20Elections%20Calendar%20Summary.pdf', 'Georgia Secretary of State – 2026 Election Calendar Highlights', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to all voters and candidates in Georgia.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('17b7198b576129d9', 'GA', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 Primary Runoff Election?', '["Primary runoff date 2026","When is the second primary round?","June runoff schedule"]', 'The 2026 General Primary Runoff Election is scheduled for Tuesday, June 16, 2026 (four weeks following the general primary).', 'https://sos.ga.gov/sites/default/files/forms/2026%20Elections%20Calendar%20Summary.pdf', 'Georgia Secretary of State – 2026 Election Calendar Highlights', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to candidates who do not secure 50% in the May primary.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('3658f70a9695b632', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election Runoff?', '["December runoff date 2026","When is the general election runoff held?","Runoff for the November election"]', 'If necessary, the 2026 General Election Runoff for state, local, and federal races will be held on Tuesday, December 1, 2026.', 'https://sos.ga.gov/sites/default/files/forms/2026%20Elections%20Calendar%20Summary.pdf', 'Georgia Secretary of State – 2026 Election Calendar Highlights', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to candidates who do not secure 50% in the November general election.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('bfc77c6a5ec3b328', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the voter registration deadline for the November 2026 General Election?', '["When do the books close for the general election?","Last day to register to vote in 2026","Registration cutoff date"]', 'The deadline to register to vote for the November 3, 2026 General Election is Monday, October 5, 2026.', 'https://sos.ga.gov/sites/default/files/forms/2026%20Elections%20Calendar%20Summary.pdf', 'Georgia Secretary of State – 2026 Election Calendar Highlights', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to all unregistered, eligible Georgia voters.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('4487e71554f29a60', 'GA', '["state"]', 'finance_ethics', 'What is the maximum individual contribution limit for a statewide candidate?', '["How much can an individual donate to a governor candidate?","Statewide campaign contribution cap","Limits for statewide races"]', 'For statewide candidates (such as Governor or Lieutenant Governor), the maximum contribution from an individual is $8,400 per primary election, $8,400 per general election, and an additional $4,800 for runoff elections.', 'https://ethics.ga.gov/campaign-contribution-limits/', 'Georgia Government Transparency and Campaign Finance Commission', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to candidates for statewide office and their donors.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('c443914b38f93037', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the contribution limit for State Legislature and local candidates?', '["How much can I donate to a state representative?","Local office contribution cap","Campaign finance limits for county commission"]', 'For state legislative, county, and municipal candidates, the maximum contribution limit from an individual is $3,300 per primary election, $3,300 per general election, and an additional $1,800 for runoff elections.', 'https://ethics.ga.gov/campaign-contribution-limits/', 'Georgia Government Transparency and Campaign Finance Commission', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to non-statewide state, legislative, and local candidates.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('8ad7dbecafea3740', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can corporations donate directly to campaigns in Georgia?', '["Are corporate contributions legal?","Can my LLC write a check to a candidate?","Business donations to politicians"]', 'Yes. Unlike federal elections, Georgia law permits corporations, LLCs, and other business entities to make direct contributions to state and local political campaigns. These are subject to the same strict contribution limits that apply to individual donors.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-41/', 'O.C.G.A. § 21-5-41 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all business entities donating to state or local campaigns in Georgia.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('2cbc4528156d16eb', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the current rules for absentee ballot drop boxes?', '["Are drop boxes still allowed?","Drop box locations and hours","SB 202 drop box restrictions"]', 'Under SB 202, absentee ballot drop boxes are strictly limited to one per 100,000 active registered voters or one per early voting site, whichever is fewer. They must be located indoors at early voting locations and are exclusively accessible during active early voting hours.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-10/section-21-2-382/', 'O.C.G.A. § 21-2-382(c)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to voters returning absentee ballots and county election officials.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('7f9e00c03a38fcd2', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can my campaign hand out water or snacks to voters waiting in line?', '["Line warming rules","Is it illegal to give food to voters?","Providing water at the polls"]', 'No. Georgia law strictly prohibits any person from giving money, gifts, food, or drink (including water) to an elector within 150 feet of a polling place or within 25 feet of any voter standing in line. Only authorized poll workers may set up self-service water stations.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-11/part-1/section-21-2-414/', 'O.C.G.A. § 21-2-414(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to campaigns, volunteers, and third-party groups at polling locations.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('cfb27232f85ab342', 'GA', '["federal","state","county","judicial"]', 'ballot_access', 'When is the qualifying period for state and federal candidates for the 2026 elections?', '["When do I file for office?","March qualifying dates","Deadline to submit declaration of candidacy"]', 'Qualifying for the 2026 election cycle begins at 9:00 a.m. on Monday, March 2, 2026, and ends at 12:00 Noon on Friday, March 6, 2026.', 'https://sos.ga.gov/sites/default/files/forms/2026%20Elections%20Calendar%20Summary.pdf', 'Georgia Secretary of State – 2026 Election Calendar Highlights', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to candidates seeking state, county, judicial, and federal office.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('e4e8aafde09da317', 'GA', '["state"]', 'ballot_access', 'What is the specific filing fee to run for Governor of Georgia?', '["How much to run for governor?","Gubernatorial qualifying fee","Cost to get on the statewide ballot"]', 'Based on the statutory formula of 3% of the Governor''s base annual salary ($175,000), the qualifying filing fee for Governor of Georgia is $5,250.00.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-131/', 'O.C.G.A. § 21-2-131 (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to candidates for Governor of Georgia.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('1ee2423af1f2631e', 'GA', '["federal"]', 'ballot_access', 'What is the specific filing fee to run for U.S. Senate or U.S. House in Georgia?', '["How much to run for Congress?","Congressional qualifying fee","Federal filing fee amount"]', 'Based on the statutory 3% formula applied to the standard federal congressional salary of $174,000, the qualifying fee for a candidate for U.S. House or U.S. Senate in Georgia is $5,220.00.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-131/', 'O.C.G.A. § 21-2-131 (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to candidates for U.S. Congress.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('82096ab1b58796cb', 'GA', '["state"]', 'ballot_access', 'What is the specific filing fee to run for the Georgia State Senate or State House?', '["How much to run for state legislature?","State rep qualifying fee","Cost to run for state senate"]', 'Unlike other offices that use the 3% formula, the qualifying fee for the Georgia General Assembly is a statutory flat-fee exception set strictly at $400.00.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-131/', 'O.C.G.A. § 21-2-131(a)(1)(A) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to candidates for the Georgia General Assembly.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ee979e1680774530', 'GA', '["judicial"]', 'ballot_access', 'What is the filing fee for a Superior Court Judge in Georgia?', '["How much to run for judge?","Judicial qualifying fee","Cost to get on the nonpartisan ballot for judge"]', 'The fee is based on the 3% formula applied strictly to the state-paid base salary ($141,970), explicitly excluding any local or county supplements. The qualifying fee is $4,259.10.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-131/', 'O.C.G.A. § 21-2-131(a)(1)(C) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to nonpartisan Superior Court judicial candidates.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('60cf17d37ccf4217', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'Can I collect petition signatures to get on the ballot instead of paying the filing fee?', '["Pauper''s affidavit for ballot access","Avoiding the qualifying fee","Petition alternative for candidates"]', 'Yes. A candidate who cannot afford the fee may file a pauper''s affidavit accompanied by a qualifying petition, demonstrating they are unable to pay, in lieu of paying the standard filing fee.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-132/', 'O.C.G.A. § 21-2-132(g) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates lacking the funds to pay the statutory qualifying fee.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('5fd7c53185ee27d0', 'GA', '["federal","state"]', 'ballot_access', 'How many signatures does an independent candidate need to run for statewide office?', '["Petition threshold for independent governor","Signature requirement for third-party statewide","Getting on the ballot as an independent"]', 'A nomination petition for an independent or political body candidate seeking a statewide office must be signed by registered voters equal to at least 1% of the total number of registered voters eligible to vote in the last election for that specific office.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-3/section-21-2-170/', 'O.C.G.A. § 21-2-170(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to independent and political body candidates for statewide positions.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('b8e6de53446de663', 'GA', '["federal","state","county","municipal"]', 'ballot_access', 'How many signatures does an independent candidate need to run for a local or legislative office?', '["Petition signatures for state rep","Local independent candidate requirements","Signature threshold for county commissioner"]', 'For non-statewide offices (such as U.S. House, State Legislature, or county offices), a nomination petition for an independent candidate must be signed by registered voters equal to at least 5% of the total number of registered voters eligible to vote in the last election for that specific office.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-3/section-21-2-170/', 'O.C.G.A. § 21-2-170(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to independent candidates for district-level and local offices.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('5e35fa081ce68cdf', 'GA', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the procedure and deadline for running as a write-in candidate?', '["How do I register as a write-in?","Write-in deadlines","Publishing intent to be a write-in"]', 'For a general election, a write-in candidate must file a notice of intention no earlier than January 1 and no later than the first Monday in September. They must also publish this notice in the official county gazette at least five days prior to filing.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-133/', 'O.C.G.A. § 21-2-133(a) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all individuals seeking write-in status.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('a44a7c13b23549d9', 'GA', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Does Georgia restrict who can vote in a party''s primary or runoff?', '["Are Georgia primaries closed?","Can Democrats vote in the GOP runoff?","Crossover voting rules"]', 'Georgia is an open primary state, meaning any voter can choose either party''s primary ballot. However, there is a strict crossover restriction for runoffs: if you vote in the Republican primary, you may ONLY vote in the Republican runoff. If you skipped the primary entirely, you may choose either runoff.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-6/section-21-2-224/', 'O.C.G.A. § 21-2-224(d) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all voters participating in primary and runoff elections.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('792ad936c27bf640', 'GA', '["federal","state","county","judicial"]', 'voter_interaction', 'What ID is required to vote in person in Georgia?', '["Do I need a driver''s license to vote?","Voter ID rules at the polls","Acceptable photo ID for voting"]', 'To vote in person, a voter must present a valid photo ID, which includes any state/federal government-issued photo ID, a Georgia driver''s license (even if expired), a valid employee photo ID from any government branch, a U.S. passport, or a military/tribal photo ID.', 'https://sos.ga.gov/page/georgia-voter-identification-requirements', 'Georgia Secretary of State – Voter ID Requirements', '2026-05-10', 'static', 'official_source_direct', 'Applies to all in-person voters.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('cbd2f93380f87c6b', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does a voter need ID to vote by mail in Georgia?', '["Absentee ballot ID requirements","How does SB 202 check mail-in ballots?","Do I need a copy of my ID for an absentee ballot?"]', 'Yes. Under SB 202, when requesting an absentee ballot, a voter must provide their Georgia driver''s license number or state ID number. If they do not have one, they must provide the last four digits of their Social Security number or attach a copy of an acceptable photo ID.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-10/section-21-2-381/', 'O.C.G.A. § 21-2-381(a)(1)(C)(i) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all voters requesting an absentee by mail ballot.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('357e51dff651da63', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Who enforces campaign finance laws in Georgia?', '["Who do I report campaign donations to?","Georgia campaign finance authority","Regulatory body for campaign ethics"]', 'The Georgia Government Transparency and Campaign Finance Commission (formerly known as the State Ethics Commission) is the regulatory body responsible for overseeing and enforcing all campaign finance, disclosure, and lobbying laws.', 'https://ethics.ga.gov/about-us/', 'Georgia Government Transparency and Campaign Finance Commission', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates and political committees operating in Georgia.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('062c15970bebc808', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the campaign finance reporting schedule in an election year?', '["How often do I file finance reports?","The 6-2-2 schedule","When are CCDRs due?"]', 'In an election year, candidates must file six Campaign Contribution Disclosure Reports (CCDRs). They are due January 31, April 30, June 30, September 30, October 25, and December 31.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34(c)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates running in a current election year.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('b313bede6c1d9880', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to file reports in a year when I am NOT running for office?', '["Non-election year reporting","Do I report if my campaign is dormant?","Off-year disclosure schedule"]', 'Yes. If a candidate holds office or maintains an active campaign account with funds/debt, they must file two reports during non-election years, due on June 30 and December 31.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34(c)(2) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates and officeholders in non-election years.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('d107e24e5cc0df1f', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Is it legal to accept cash contributions for my campaign?', '["Cash donation rules","Can someone give me a $200 bill?","Limits on anonymous cash"]', 'Yes, but it is strictly limited. A candidate may not accept any anonymous contribution, and any contribution of more than $100 must be made by a check or other written/electronic instrument (no cash over $100).', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-30/', 'O.C.G.A. § 21-5-30(e) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all campaigns receiving contributions.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('7522b5f0f425fa5e', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are loans from my personal bank account subject to contribution limits?', '["Can I self-fund my campaign with unlimited loans?","Do loans count as donations?","Borrowing money for the campaign"]', 'A candidate''s personal funds or personal loans to their own campaign are not subject to contribution limits. However, loans from a third party (like a business or another individual) are treated as contributions and are strictly subject to per-election limits.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-41/', 'O.C.G.A. § 21-5-41 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to campaigns utilizing loans.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('12ac058b910a4a92', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are late fees for ethics reports?","Fines for missing a deadline","Commission penalties"]', 'The Georgia Campaign Finance Commission imposes tiered late fees: $125 for reports up to 14 days late, an additional $250 if it hits 15 days late, and a further $1,000 if the report reaches 45 days late.', 'https://ethics.ga.gov/late-fees/', 'Georgia Government Transparency and Campaign Finance Commission – Late Fees', '2026-05-10', 'per_cycle', 'official_source_direct', 'Applies to all candidates failing to file disclosure reports on time.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('319da11205d8b8e6', 'GA', '["state","county","municipal","judicial"]', 'finance_ethics', 'What has to be disclosed on a Personal Financial Disclosure Statement (PFDS)?', '["What do I have to reveal about my income?","Reporting business interests","Details required on the PFDS"]', 'A candidate must disclose all corporate/LLC officerships and directorships, a list of all businesses where they own more than 5% or $5,000 in stock, any state business contracts they hold, and real estate holdings valued over $5,000.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-3/section-21-5-50/', 'O.C.G.A. § 21-5-50(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to state and local candidates filing personal financial disclosures.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('1ccf68a5623f73b8', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to use a separate bank account just for campaign funds?', '["Can I use my personal checking account?","Campaign depository rules","Commingling campaign and personal money"]', 'Yes. Campaign funds must be maintained in a separate campaign depository (bank account) opened in the name of the campaign. Commingling campaign funds with personal or business funds is strictly prohibited.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-30/', 'O.C.G.A. § 21-5-30(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidate financial accounting.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('a1445c8e2b0e58c0', 'GA', '["state","county"]', 'ballot_access', 'Can I sign a declaration of candidacy if I have outstanding ethics fines?', '["Can I run if I owe the state money?","Past due ethics fines and qualifying","DQ-1 form requirements"]', 'No. When completing the Declaration of Candidacy (DQ-1) form, a candidate must swear under oath that they do not owe any outstanding fines or fees to the Georgia Government Transparency and Campaign Finance Commission.', 'https://sos.ga.gov/sites/default/files/forms/2023-11/Declaration_of_Candidacy.pdf', 'Georgia Secretary of State – Declaration of Candidacy Form', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates executing qualifying paperwork.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('efe03ed7ca3bf7b8', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'How is the order of candidate names determined on the Georgia primary ballot?', '["Who gets the top spot?","Is ballot order alphabetical?","Drawing lots for ballot placement"]', 'For primary elections, candidate names are determined by an alphabetical arrangement of the candidates'' surnames. They are not drawn randomly or rotated by precinct in Georgia.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-8/section-21-2-284/', 'O.C.G.A. § 21-2-284(c) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates appearing on a primary ballot.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('961456be5f599fa8', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'What happens if I want to withdraw my candidacy after I qualify?', '["How do I quit the race?","Removing my name from the ballot","Withdrawal procedures"]', 'A candidate may withdraw by filing a notarized affidavit of withdrawal with the Secretary of State or their local election superintendent. If withdrawn before ballots are printed, the name is removed; if after, notices are posted at polls that votes for them will not be counted.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-134/', 'O.C.G.A. § 21-2-134(a)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates wishing to officially terminate their campaign.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('30f980deac75b362', 'GA', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'Does Georgia have a ''Sore Loser'' law preventing me from running as an independent if I lose the primary?', '["Can a primary loser run in the general?","Running as a write-in after losing","Sore loser prohibitions"]', 'Yes. Under Georgia law, a candidate who is defeated in a political party primary is strictly prohibited from running for the same office in the succeeding general election as an independent, a political body candidate, or a write-in candidate.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-4/part-1/section-21-2-137/', 'O.C.G.A. § 21-2-137 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates defeated in a partisan primary.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('6eeef470fd73416c', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'runoff_rules', 'Can I qualify to run in a runoff election if I didn''t participate in the primary?', '["Jumping into a runoff","Can new candidates enter a runoff?","Runoff ballot access"]', 'No. A runoff election is strictly a continuation of the original election. Only the candidates who received the two highest numbers of votes in the original election advance to the runoff; no new candidates may enter, and write-in votes are not allowed.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(6) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to ballot access for runoff elections.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('46bf2e4d5de4c0e9', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'If a voter registers after the primary, can they vote in the primary runoff?', '["Runoff voter registration","Can new residents vote in the runoff?","Does the registration book reopen for runoffs?"]', 'No. Only electors who were duly registered to vote in the original primary or general election are eligible to vote in the subsequent runoff. The voter registration books do not ''reopen'' between the main election and the runoff.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(5) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to voter eligibility for runoff elections.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('46dae0655b582999', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I need to register a campaign committee before accepting donations?', '["When do I file my treasurer paperwork?","Declaring intent to raise funds","Form DOI requirement"]', 'Yes. A candidate must file a Declaration of Intention to Accept Campaign Contributions (Form DOI) with the Commission or their local filing officer before accepting any campaign contributions.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-30/', 'O.C.G.A. § 21-5-30(g) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all state and local candidates intending to raise money.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('d13683e9f0d2ffaf', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'How long is the early voting period for a primary or general election?', '["When does advanced voting start?","Duration of early voting window","Georgia early voting dates"]', 'Advanced (early) voting in Georgia begins on the fourth Monday prior to a primary or general election, continuing for three full weeks. The schedule specifically mandates at least two Saturdays of early voting.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-10/section-21-2-385/', 'O.C.G.A. § 21-2-385(d)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all standard primary and general elections.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('6f38d2875b754400', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'How long is early voting for a runoff election?', '["Early voting for the general runoff","Runoff advanced voting timeline","When does early voting start for the runoff?"]', 'Because general election runoffs were dramatically shortened to a four-week window under SB 202, early voting for a runoff must begin as soon as possible, but no later than the second Monday prior to the runoff election.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-10/section-21-2-385/', 'O.C.G.A. § 21-2-385(d)(1)(B) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all state and federal runoff elections.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('5ecde4ac7b1863eb', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What time do polls close on Election Day in Georgia?', '["Voting hours","When does the voting location shut down?","Poll closing time"]', 'On Election Day, polls in Georgia are open from 7:00 a.m. to 7:00 p.m. Any voter who is physically in line by 7:00 p.m. must be allowed to cast their ballot.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-11/part-1/section-21-2-403/', 'O.C.G.A. § 21-2-403 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all in-person voting operations on Election Day.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ac8ab57b5882cf2c', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline for a voter to return an absentee ballot?', '["Mail ballot deadline","Does postmark matter for mail ballots?","How late can an absentee ballot arrive?"]', 'Absentee ballots must be physically received by the county Board of Registrars by the close of polls (typically 7:00 p.m.) on Election Day. A postmark on Election Day is not sufficient; the ballot must be in their possession.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-10/section-21-2-386/', 'O.C.G.A. § 21-2-386(a)(1)(F) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to domestic civilian voters returning mail ballots.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('49f6274625f7db6c', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to file campaign finance reports if I don''t raise or spend more than $2,500?', '["Exemption from reporting","Affidavit of intent not to exceed limits","Short form reporting"]', 'A candidate who files a sworn affidavit with the Commission that they do not intend to accept contributions or make expenditures exceeding $2,500 for the entire election cycle is exempt from filing the standard 6-2-2 schedule disclosure reports.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34(c) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to candidates running low-budget campaigns.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('2d3234635556c2d6', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the basic voter eligibility requirements in Georgia?', '["Who can register to vote?","Voting age and citizenship","Can out of state college students vote?"]', 'To register to vote in Georgia, an individual must be a U.S. citizen, a legal resident of the county in which they seek to vote, and at least 17 and a half years of age (or within six months of their 18th birthday) to register, though they must be 18 to cast a ballot.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-6/section-21-2-216/', 'O.C.G.A. § 21-2-216(c) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all individuals seeking to register to vote.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('a3eb7565e387b01f', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can an individual with a felony conviction vote in Georgia?', '["Felony voting rights","Can felons vote after prison?","Restoration of rights in Georgia"]', 'Yes, but only after they have fully completed their sentence. Georgia law stipulates that rights are restored only upon the completion of all probation, parole, and the payment of any court-ordered fines associated with the felony conviction.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-6/section-21-2-216/', 'O.C.G.A. § 21-2-216(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to Georgia residents with past felony convictions.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('7a8b69ed5bdc6759', 'GA', '["state"]', 'residency', 'What are the residency and age requirements to run for Governor of Georgia?', '["How old to run for governor?","Residency rules for statewide office","Qualifications for governor"]', 'A candidate for Governor must be at least 30 years old on the day they assume office, must have been a U.S. citizen for 15 years, and must have been a legal resident of Georgia for the 6 years immediately preceding the election.', 'https://law.justia.com/constitution/georgia/article-v/section-i/paragraph-iv/', 'Georgia Constitution, Article V, Section I, Paragraph IV (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates for Governor and Lieutenant Governor.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('6ffeaf80c6530a58', 'GA', '["state"]', 'residency', 'What are the residency and age requirements to run for the Georgia State Legislature?', '["How old to run for state house?","Residency rules for state senate","District residency timeline"]', 'State Senators must be 25 years old; State Representatives must be 21. Both must be U.S. citizens, citizens of Georgia for at least two years, and legal residents of the district they seek to represent for at least one year prior to the election.', 'https://law.justia.com/constitution/georgia/article-iii/section-ii/paragraph-iii/', 'Georgia Constitution, Article III, Section II, Paragraph III (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates for the Georgia General Assembly.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('7182a82fa2e6e62b', 'GA', '["state","county","municipal","special_district"]', 'recall_rules', 'On what legal grounds can an elected official be recalled in Georgia?', '["Recall justification","Can we recall a mayor for bad policy?","Reasons required for a recall petition"]', 'Under the Recall Act of 1989, a recall petition must allege specific statutory grounds: acts of malfeasance, misconduct, incompetence, failure to perform prescribed duties, or conviction of a crime involving moral turpitude.', 'https://law.justia.com/codes/georgia/title-21/chapter-4/section-21-4-3/', 'O.C.G.A. § 21-4-3(7) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to voters initiating a recall of state or local officials.', 'batch_2026-05-10T15-46-55_georgia_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('902a6fa9586c7949', 'GA', '["state","county","municipal","special_district"]', 'recall_rules', 'How many signatures are required to trigger a recall election?', '["Recall signature threshold","How many people need to sign to recall the governor?","Math for recall petitions"]', 'For statewide officials, signatures must equal 15% of the number of electors who voted in the preceding election for that office. For local, county, or district officials, the threshold is a very high 30% of the electors registered to vote at the last preceding election for that office.', 'https://law.justia.com/codes/georgia/title-21/chapter-4/section-21-4-4/', 'O.C.G.A. § 21-4-4(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to organizers of recall petitions.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('72b5e8190312d47d', 'GA', '["state","county","municipal","special_district"]', 'recall_rules', 'How long do organizers have to collect signatures for a recall petition?', '["Recall timeline","Deadline to submit recall signatures","Time limit on circulating petitions"]', 'Once the official petition forms are issued, sponsors have exactly 90 days to collect signatures for a statewide office, 45 days for local/county offices, and 30 days for members of the General Assembly.', 'https://law.justia.com/codes/georgia/title-21/chapter-4/section-21-4-11/', 'O.C.G.A. § 21-4-11(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all statutory recall efforts.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('679a3db1ae1fc01a', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'runoff_rules', 'What happens if a candidate who qualifies for a runoff withdraws or dies?', '["Withdrawing from a runoff","Does the third place candidate move up?","Canceling a runoff election"]', 'If one of the two candidates qualifying for a runoff withdraws or dies before the runoff, the remaining candidate is immediately declared the winner. The candidate who finished third in the initial election does NOT move up to replace them.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(6) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all runoff elections.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('3e166f4404e7cc6a', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What legally constitutes an ''Independent Expenditure'' in Georgia?', '["Definition of independent expenditure","PAC spending rules","What makes a Super PAC independent?"]', 'An independent expenditure is an expenditure for a communication that expressly advocates the election or defeat of a clearly identified candidate, which is made entirely without the cooperation, consent, or prior consultation of the candidate or their committee.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-1/section-21-5-3/', 'O.C.G.A. § 21-5-3(15) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to third parties and PACs making political expenditures.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('e9637e87ae9f1d51', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If an outside group coordinates an ad with my campaign, how is it reported?', '["Coordinated ad rules","Does a coordinated PAC ad count as a donation?","Reporting shared expenses"]', 'If an expenditure is coordinated with the candidate or their campaign, it loses its ''independent'' status and is legally classified as an ''in-kind'' contribution to the campaign. It must be reported as such and is strictly subject to the candidate''s contribution limits.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-41/', 'O.C.G.A. § 21-5-41(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to campaigns interacting with outside groups.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('db48007131d95ae0', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When does an ''Independent Committee'' have to register with the state?', '["Registering a PAC","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'Any independent committee (PAC) that accepts contributions or makes independent expenditures aggregating more than $500 in a calendar year must register with the Commission and file periodic disclosure reports.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34(e) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to political action committees and independent expenditure groups.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('5a6be7bba8cd2f68', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I value an in-kind contribution of goods or services?', '["In-kind valuation","How much is a donated venue worth?","Reporting free services"]', 'In-kind contributions (such as donated food, venue space, or professional printing) must be valued at the current fair market retail value of the goods or services provided, and they count directly against the donor''s per-election contribution limit.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-1/section-21-5-3/', 'O.C.G.A. § 21-5-3(7) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns accepting non-monetary donations.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('dbd0716e273006ff', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I transfer surplus campaign funds to run for a different office?', '["Rolling over campaign money","Using old funds for a new race","Transferred funds rules"]', 'No. While you may carry forward surplus funds to a future election for the *same* office, Georgia law prohibits transferring campaign funds to a campaign for a *different* elective office.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33(b)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates seeking to change the office they are running for.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('378d4a7bae66d105', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign request a formal legal opinion on an ethics issue?', '["Ethics advisory opinions","How do I ask the commission a question?","Getting a ruling on campaign finance"]', 'Yes. A candidate or their committee may request a written advisory opinion from the Georgia Government Transparency and Campaign Finance Commission regarding the interpretation of the Campaign Finance Act. Conduct following an advisory opinion provides a legal safe harbor.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-1/section-21-5-6/', 'O.C.G.A. § 21-5-6(b)(13) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates seeking clarification on finance/ethics laws.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('b016605e813c5315', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the rules for poll watcher conduct inside the voting location?', '["Can poll watchers talk to voters?","Using phones as an observer","Poll watcher restrictions"]', 'Poll watchers are strictly prohibited from interfering with the election, talking to voters, campaigning, or using photographic or electronic recording devices (including cell phones) while inside the enclosed space of the polling place.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-11/part-1/section-21-2-408/', 'O.C.G.A. § 21-2-408(d) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to designated poll watchers.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ab9b7d232b0e6afa', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Under what circumstances is a voter issued a provisional ballot?', '["Why do people vote provisionally?","What if a voter isn''t on the rolls?","Voting without an ID"]', 'A provisional ballot is issued if a voter''s name does not appear on the official electors list for the precinct, if they cannot produce the required photo ID, or if a poll officer challenges their eligibility to vote at that specific precinct.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-11/part-1/section-21-2-418/', 'O.C.G.A. § 21-2-418(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to voters facing eligibility issues at the polls.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ab88cf337339e88f', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How long does a voter have to ''cure'' a provisional ballot so it gets counted?', '["Provisional ballot deadline","How late can I show my ID after voting?","Curing a provisional vote"]', 'If a voter casts a provisional ballot (e.g., for lack of photo ID), they have until the close of business on the Friday following the election to provide the required ID or evidence of eligibility to the county registrar''s office.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-11/part-1/section-21-2-418/', 'O.C.G.A. § 21-2-418(c) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to voters who cast provisional ballots.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('19981968974facd2', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are campaign signs allowed in the public right-of-way?', '["Can I put signs in the median?","Highway campaign sign rules","Does the state take down political signs?"]', 'No. Georgia law strictly prohibits the placement of political signs on the public right-of-way of any state highway, road, or street. Unauthorized signs are considered litter and may be immediately removed by the Department of Transportation or local authorities.', 'https://law.justia.com/codes/georgia/title-32/chapter-6/article-3/part-2/section-32-6-51/', 'O.C.G.A. § 32-6-51(b)(3) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns placing signage.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('29b1ee089d587c87', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does the state set a strict deadline for when campaign signs must be taken down after the election?', '["When do I have to remove yard signs?","Post-election signage removal","How long can signs stay up?"]', 'While the state bans signs on public rights-of-way entirely, the specific deadlines for removing signs from private property post-election (often 30 days) are governed individually by local municipal and county zoning ordinances, not state statute.', 'https://law.justia.com/codes/georgia/title-32/chapter-6/article-3/part-2/section-32-6-51/', 'O.C.G.A. § 32-6-51 (Context) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns conducting field operations.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('a6941a9d33311139', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the disclaimer rules for campaign robocalls?', '["Robocall rules","Voice call political advertising","Do auto-dialers need to say who paid for it?"]', 'Automated political calls (robocalls) must clearly state the identity of the person or organization paying for the call at the beginning of the message. Furthermore, federal law prohibits making automated calls to cell phones without the recipient''s prior express consent.', 'https://law.justia.com/codes/georgia/title-46/chapter-5/article-2/section-46-5-27/', 'O.C.G.A. § 46-5-27 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns conducting phone outreach.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('33f637af9415b0d6', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Do SMS text messages sent to voters require a political disclaimer?', '["Text messaging campaign rules","Do campaign texts need disclaimers?","Mass texting disclosure"]', 'Yes. Campaign text messages fall under general political advertising regulations and FCC/TCPA rules. Mass texts must include a ''Paid for by'' disclaimer and opt-out instructions, and sending them using an autodialer requires the recipient''s prior consent.', 'https://ethics.ga.gov/wp-content/uploads/2021/04/Candidate-Guide-2021.pdf', 'Georgia Ethics Commission – General Advertising Context', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns using mass SMS.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('25e27861ca82c114', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does Georgia require candidates to open a separate ''Officeholder Account'' after they win?', '["Officeholder account rules","Do I need a new bank account once elected?","Keeping the campaign account open"]', 'No. Georgia law does not mandate a separate ''officeholder account.'' An elected official may retain their campaign account and use surplus funds for ordinary and necessary expenses incurred in connection with the holding of public office.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to successful candidates transitioning to officeholders.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ddb649637f623563', 'GA', '["federal","state"]', 'redistricting', 'If my district boundaries change due to redistricting, when must I establish residency in the new district?', '["Redistricting impact on residency","Do new map lines ruin my 1-year residency?","Running in a redrawn district"]', 'If a candidate''s legislative district is altered by reapportionment, the Georgia Constitution generally requires them to be a legal resident of the newly drawn district at the time of their election, but courts often afford specific transition windows depending on the timing of the map''s adoption.', 'https://law.justia.com/constitution/georgia/article-iii/section-ii/paragraph-iii/', 'Georgia Constitution, Article III, Section II, Paragraph III (Secondary/Justia)', '2026-05-10', 'volatile', 'secondary_source', 'Applies to candidates in districts altered by mid-cycle redistricting.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('24273fbdf246e531', 'GA', '["federal"]', 'candidate_eligibility', 'What are the specific eligibility requirements to run for U.S. Senate in Georgia?', '["Age to run for US Senate","Federal Senate qualifications","Residency rules for federal office"]', 'A candidate for U.S. Senate must be at least 30 years old, a citizen of the United States for at least nine years, and must be an ''inhabitant'' of Georgia when elected, as determined by the U.S. Constitution.', 'https://sos.ga.gov/qualifying-candidate-information', 'Georgia Secretary of State – Qualifying Qualifications', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the United States Senate.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('8a6cef77cc18be0e', 'GA', '["federal"]', 'candidate_eligibility', 'What are the specific eligibility requirements to run for U.S. House in Georgia?', '["Age to run for Congress","US Representative qualifications","Do I have to live in my congressional district?"]', 'A candidate for U.S. House must be at least 25 years old, a U.S. citizen for at least seven years, and an ''inhabitant'' of Georgia when elected. Crucially, the U.S. Constitution does NOT require the candidate to live within the specific district boundaries.', 'https://sos.ga.gov/qualifying-candidate-information', 'Georgia Secretary of State – Qualifying Qualifications', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the United States House of Representatives.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('2460d70aa24eec6e', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If someone volunteers for my campaign, is their time considered an in-kind contribution?', '["Reporting volunteer hours","Do I have to claim free consulting time?","Is volunteer labor a donation?"]', 'No. The value of personal services performed by persons who serve without compensation on a voluntary basis is expressly excluded from the definition of a contribution under Georgia law.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-1/section-21-5-3/', 'O.C.G.A. § 21-5-3(7)(B)(i) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns utilizing volunteer labor.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('b249c91873d557c9', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept donations from foreign nationals?', '["Accepting money from non-citizens","Foreign contributions in Georgia","Can someone from overseas donate?"]', 'No. Federal law strictly prohibits foreign nationals from directly or indirectly making contributions or donations of money or other things of value in connection with ANY federal, state, or local election.', 'https://ethics.ga.gov/wp-content/uploads/2021/04/Candidate-Guide-2021.pdf', 'Georgia Ethics Commission – General Advertising Context', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns and political committees.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('cf7d4975dc8fccd6', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do Political Action Committees (PACs) file reports on the same schedule as candidates?', '["PAC reporting schedule","When do independent committees file?","Third-party disclosure dates"]', 'Independent committees (PACs) that participate in an election generally follow the same 6-2-2 schedule (6 times in an election year, 2 in off-years) as the candidates they are supporting or opposing.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34(e) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to PACs operating in Georgia.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('625064b23b62fba2', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Are political parties subject to the same contribution limits as standard PACs?', '["Party committee contribution limits","Can the GOP give me unlimited money?","State party funding rules"]', 'No. Contributions from political party committees are treated distinctly. They are not subject to the standard individual/PAC contribution limits when supporting their party''s candidates, allowing them to provide more substantial financial backing.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-41/', 'O.C.G.A. § 21-5-41 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates receiving party support.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('3e93502361c4d0d2', 'GA', '["state","county","municipal","special_district"]', 'finance_ethics', 'Does a committee formed to support a ballot measure have to register and file reports?', '["Ballot proposition committees","Reporting issue advocacy","Do tax referendum campaigns file ethics reports?"]', 'Yes. Any ''campaign committee'' that accepts contributions or makes expenditures designed to bring about the approval or rejection of a ballot question must register with the Commission and file periodic disclosure reports.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34(e) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to organizations advocating for or against ballot measures.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('f5958f48f8a24fed', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If two candidates host a joint fundraiser, how are the costs and contributions handled?', '["Joint fundraising rules","Sharing campaign event costs","Splitting money with another candidate"]', 'Candidates participating in a joint fundraiser must strictly allocate both the contributions received and the expenditures (costs) of the event proportionally between their separate campaign committees. Funds cannot be commingled in a single un-allocated pool.', 'https://ethics.ga.gov/wp-content/uploads/2021/04/Candidate-Guide-2021.pdf', 'Georgia Ethics Commission – General Guidance', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns pooling resources for events.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('25f931416e807e43', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to report payments made to Facebook or Google for digital ads?', '["Reporting online advertising","Digital ad disclosure","Are internet ads considered campaign expenditures?"]', 'Yes. Payments made for digital, social media, or internet advertising are classified as campaign expenditures and must be itemized on the Campaign Contribution Disclosure Report (CCDR) like any other vendor payment.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns purchasing online media.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('95ae66a0eff12e6e', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can the state political party pay for an ad that explicitly tells people to vote for me?', '["Coordinated party expenditures","Can the GOP buy ads for my race?","Party spending on behalf of candidates"]', 'Yes. A political party committee may make coordinated expenditures on behalf of their party''s nominees. Unlike standard PACs, these party expenditures enjoy higher legal thresholds and are a standard mechanism for supporting down-ballot candidates.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-41/', 'O.C.G.A. § 21-5-41 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates receiving party support.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('56ef692a9f9f483e', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How long must my campaign treasurer keep our financial records?', '["Record retention rules","How long do I save receipts?","Keeping finance reports post-election"]', 'Campaign treasurers must maintain detailed accounts, records, and receipts for a period of three (3) years from the date of the election to which the records pertain.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-30/', 'O.C.G.A. § 21-5-30(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaign treasurers and candidates.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('1fe47226a793430c', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I officially close my campaign account after the election?', '["Ending my campaign reporting obligations","Filing the termination report","How to stop filing ethics reports"]', 'To end reporting obligations, a candidate must file a Final Report (Termination Report) indicating a zero balance, no outstanding debts, and confirming that all surplus funds have been properly disposed of under state law.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-34/', 'O.C.G.A. § 21-5-34 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates wishing to terminate their campaign treasurer appointment.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('78d7dee889e480b2', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I keep the laptop and printer my campaign bought after the election is over?', '["Keeping campaign equipment","Post-election use of campaign assets","Can I take campaign property home?"]', 'No. Campaign equipment cannot be converted to personal use. If a candidate wishes to keep physical assets purchased by the campaign, they must purchase them from the campaign account at fair market value before closing it.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to campaigns liquidating physical assets.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('2ce0c8ed6d9fb4b5', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the exact deadline to request a mail-in ballot for the November 2026 General Election?', '["When is the last day to request an absentee ballot in 2026?","Fall absentee request cutoff","SB 202 deadline for mail ballots"]', 'Under the 11-day statutory rule, the deadline for the county to receive an absentee ballot request for the November 3, 2026 General Election is Friday, October 23, 2026.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-10/section-21-2-381/', 'O.C.G.A. § 21-2-381(a)(1)(A) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to voters requesting to vote by mail in the Fall.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ed4e78264cbd354e', 'GA', '["federal","state","county","municipal","judicial","special_district"]', 'runoff_rules', 'If I am not registered to vote for the May primary, can I register in time for the June primary runoff?', '["Can new voters vote in the primary runoff?","Runoff registration deadline","Registering between the primary and the runoff"]', 'No. Georgia law prohibits registering to vote specifically for a runoff. You must have been registered and eligible to vote in the original May primary election to be legally eligible to cast a ballot in the subsequent June primary runoff.', 'https://law.justia.com/codes/georgia/title-21/chapter-2/article-12/part-1/section-21-2-501/', 'O.C.G.A. § 21-2-501(a)(5) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to unregistered voters during the primary cycle.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('86be0da4972dc097', 'GA', '["federal"]', 'residency', 'Does a candidate for U.S. House have to live in the district they are running for?', '["Federal residency rules","Can I run in a district I don''t live in?","Carpetbagging in congressional races"]', 'No. The U.S. Constitution requires a Representative to be an ''inhabitant'' of the *state* in which they are chosen when elected, but it does not require them to reside within the specific boundaries of the congressional district.', 'https://sos.ga.gov/qualifying-candidate-information', 'Georgia Secretary of State – Candidate Qualifications', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the U.S. House of Representatives.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('92e835d49feb6d6c', 'GA', '["state","county","municipal","judicial"]', 'finance_ethics', 'If I lose my primary election, do I have to return contributions given for the general election?', '["Refunding general election money if I lose the primary","Can I keep funds if I don''t make the general?","Returning donations after a defeat"]', 'Yes. If a candidate accepts contributions explicitly designated for the general election but is defeated in the primary, those general election contributions must be returned to the donors within ten (10) days of the primary loss.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33(c) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates who accept funds for future election cycles they do not reach.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('5e6df49e6efac601', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay for legal defense?', '["Paying lawyers with donor money","Are legal fees a campaign expense?","Defending against ethics complaints"]', 'Yes, but strictly limited. Campaign funds may be used to pay for attorney''s fees and costs incurred exclusively in connection with the campaign for office or the performance of official duties (such as defending against a Commission ethics complaint).', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates facing legal or ethics challenges.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('ae088874de7aec1a', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I pay myself a salary from my campaign funds?', '["Candidate salary from campaign","Paying myself to run for office","Is candidate compensation legal?"]', 'No. Georgia law strictly prohibits the personal use of campaign funds. A candidate may not draw a salary or compensation from their own campaign committee.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates managing campaign accounts.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('71ee1eac315126ea', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign website or digital ad require a ''Paid for by'' disclaimer?', '["Digital advertising disclaimers","Do Facebook ads need disclosures?","Website paid-for rules"]', 'Yes. Political advertising published in print, broadcast on TV/radio, or distributed via digital advertising platforms (like Facebook or Google) must include a clear disclosure stating who paid for the communication.', 'https://ethics.ga.gov/wp-content/uploads/2021/04/Candidate-Guide-2021.pdf', 'Georgia Ethics Commission – Advertising Guidance', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns running digital or print advertisements.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('af368f9e7d2f2048', 'GA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'If I end my campaign, how do I return surplus funds to my donors?', '["Refunding contributors","How to give money back after an election","Surplus fund disposal pro-rata"]', 'If a candidate chooses to return surplus funds to contributors, the funds must be returned pro-rata (proportionally) to each person who contributed, based on the amount they gave.', 'https://law.justia.com/codes/georgia/title-21/chapter-5/article-2/section-21-5-33/', 'O.C.G.A. § 21-5-33(b)(1)(C) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates terminating operations and distributing surplus.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('e39f2a6debc5d3b0', 'GA', '["state","county","municipal","judicial","special_district"]', 'filing_requirements', 'Do I have to register with the state if I hire an out-of-state political consulting firm?', '["Hiring out of state vendors","Do my consultants need a Georgia license?","Paying DC firms"]', 'While the campaign does not need special permission to hire them, any out-of-state business entity (LLC, Corporation) consistently conducting business inside Georgia must register as a foreign business entity with the Georgia Secretary of State''s Corporations Division.', 'https://sos.ga.gov/corporations-division-georgia-secretary-state', 'Georgia Secretary of State – Corporations Division', '2026-05-10', 'static', 'official_source_direct', 'Applies to campaigns employing out-of-state vendors.', 'batch_2026-05-10T15-46-55_georgia_full_v1'),
  ('e6b97dff1a138773', 'GA', '["state"]', 'finance_ethics', 'If I am a registered lobbyist, what are the restrictions on interacting with campaigns?', '["Can lobbyists donate to candidates?","Lobbying rules and campaign finance","Restrictions on lobbyist activity"]', 'A registered lobbyist in Georgia may donate to campaigns subject to standard limits, but they are subject to strict transparency rules and must file separate lobbying disclosure reports detailing any expenditures made on behalf of public officers.', 'https://ethics.ga.gov/lobbyist/', 'Georgia Government Transparency and Campaign Finance Commission – Lobbying', '2026-05-10', 'static', 'official_source_direct', 'Applies to registered lobbyists engaging with campaigns.', 'batch_2026-05-10T15-46-55_georgia_full_v1')
